// ——— Storage ———
// ——— Shared Storage Cache ———
// Lädt alle Tage einmal und teilt sie zwischen Verlauf/Analyse
let _daysCache = null;
let _daysCachePromise = null;
let _configCache = {};

async function getConfigCached(type) {
  if (_configCache[type]) return _configCache[type];
  _configCache[type] = await loadConfig(type);
  return _configCache[type];
}

function invalidateConfigCache(type) {
  if (type) delete _configCache[type];
  else _configCache = {};
}

async function getAllDays(forceReload = false) {
  if (!forceReload && _daysCache) return _daysCache;
  if (_daysCachePromise) return _daysCachePromise;

  _daysCachePromise = (async () => {
    const list = await window.storage.list("day:");
    const keys = (list && list.keys) ? list.keys.sort() : [];
    const entries = await Promise.all(
      keys.map(async (k) => {
        const res = await window.storage.get(k);
        try {
          return { date: k.replace("day:", ""), data: res ? JSON.parse(res.value) : null };
        } catch {
          return null;
        }
      })
    );
    _daysCache = entries.filter((e) => e && e.data);
    _daysCachePromise = null;
    return _daysCache;
  })();
  return _daysCachePromise;
}

function invalidateDaysCache() {
  _daysCache = null;
  _daysCachePromise = null;
}

async function saveDay(dateStr, data) {
  try {
    await window.storage.set(`day:${dateStr}`, JSON.stringify(data));
    // Cache inline aktualisieren wenn möglich, sonst invalidieren
    if (_daysCache) {
      const existing = _daysCache.find((d) => d.date === dateStr);
      if (existing) {
        existing.data = data;
      } else {
        _daysCache.push({ date: dateStr, data });
        _daysCache.sort((a, b) => a.date.localeCompare(b.date));
      }
    }
    return true;
  } catch (e) {
    console.error(e);
    invalidateDaysCache();
    return false;
  }
}

async function loadDay(dateStr) {
  try {
    const r = await window.storage.get(`day:${dateStr}`);
    if (!r) return null;
    const parsed = JSON.parse(r.value);
    return {
      ...emptyDay(),
      ...parsed,
      sleep: { ...emptyDay().sleep, ...(parsed.sleep || {}) },
      meal: { ...emptyDay().meal, ...(parsed.meal || {}) },
      watch: { ...emptyDay().watch, ...(parsed.watch || {}) },
      active: {
        supplements: (parsed.active && parsed.active.supplements) || {},
        medications: (parsed.active && parsed.active.medications) || {},
        peptides: (parsed.active && parsed.active.peptides) || {},
      },
    };
  } catch {
    return null;
  }
}

async function loadConfig(type) {
  try {
    const r = await window.storage.get(`config:${type}`);
    if (r) return JSON.parse(r.value);
  } catch {}
  // Fallback: Defaults
  return TYPE_CONFIG[type].defaults.map((d) => ({ ...d, isCustom: false }));
}

async function saveConfig(type, list) {
  try {
    await window.storage.set(`config:${type}`, JSON.stringify(list));
    _configCache[type] = list; // Cache inline updaten
  } catch (e) {
    console.error(e);
    invalidateConfigCache(type);
  }
}



// ——— Health Auto Export Parser ———
// Versucht flexibel, verschiedene JSON-Formate zu erkennen
function parseHealthExport(json) {
  // Sammelt alle erkannten Tage: { "2026-04-17": { deep, rem, light, wake, hrv, restingHR, totalSleep } }
  const result = {};
  let unrecognized = [];

  // Normalisierung: möglichen Wurzelpfad finden
  let data = json;
  if (json.data && typeof json.data === "object") data = json.data;
  if (json.metrics && Array.isArray(json.metrics)) data = { metrics: json.metrics };

  // Format 1: Health Auto Export Standard -> { "data": { "metrics": [{ name, data: [...] }] } }
  const metrics = data.metrics || json.metrics || [];
  if (Array.isArray(metrics) && metrics.length > 0) {
    for (const metric of metrics) {
      const name = (metric.name || "").toLowerCase();
      const entries = metric.data || [];
      if (!Array.isArray(entries)) continue;

      for (const entry of entries) {
        // Datum bestimmen (endDate meist relevanter für Schlaf)
        const dateStr = (entry.endDate || entry.date || entry.startDate || "").slice(0, 10);
        if (!dateStr) continue;

        if (!result[dateStr]) {
          result[dateStr] = { deep: 0, rem: 0, light: 0, wake: 0, totalSleep: 0, hrv: null, restingHR: null };
        }

        // Schlafphasen erkennen
        if (name.includes("sleep_analysis") || name.includes("schlaf") || name.includes("sleep")) {
          const value = (entry.value || entry.qty || "").toString().toLowerCase();
          const hours = Number(entry.qty || entry.duration || entry.value || 0);
          if (value.includes("deep") || name.includes("deep")) result[dateStr].deep += hours;
          else if (value.includes("rem") || name.includes("rem")) result[dateStr].rem += hours;
          else if (value.includes("core") || value.includes("light") || name.includes("light")) result[dateStr].light += hours;
          else if (value.includes("awake") || value.includes("wach") || name.includes("awake")) result[dateStr].wake += hours;
          else if (value.includes("inbed") || value.includes("asleep")) result[dateStr].totalSleep += hours;
        }
        // HRV
        else if (name.includes("heart_rate_variability") || name.includes("hrv")) {
          const qty = Number(entry.qty || entry.value || 0);
          if (qty > 0) result[dateStr].hrv = Math.round(qty * 10) / 10;
        }
        // Ruhepuls
        else if (name.includes("resting_heart_rate") || name.includes("resting")) {
          const qty = Number(entry.qty || entry.value || 0);
          if (qty > 0) result[dateStr].restingHR = Math.round(qty);
        }
      }
    }
  } else {
    unrecognized.push("Kein 'metrics'-Array gefunden");
  }

  // Runden auf 1 Nachkommastelle
  for (const d in result) {
    result[d].deep = Math.round(result[d].deep * 10) / 10;
    result[d].rem = Math.round(result[d].rem * 10) / 10;
    result[d].light = Math.round(result[d].light * 10) / 10;
    result[d].wake = Math.round(result[d].wake * 10) / 10;
    result[d].totalSleep = Math.round(result[d].totalSleep * 10) / 10;
  }

  return { days: result, unrecognized };
}

async function importHealthData(parsed) {
  let created = 0;
  let updated = 0;
  let merged = 0;

  for (const date in parsed.days) {
    const existing = await loadDay(date);
    const base = existing || emptyDay();
    const existingWatch = base.watch || {};
    const newWatch = parsed.days[date];

    // Smart Merge: leere/null Werte in neuem Import überschreiben NICHT bestehende Daten
    const mergedWatch = { ...existingWatch };
    let hadChange = false;

    for (const key in newWatch) {
      const newVal = newWatch[key];
      // Nur überschreiben, wenn der neue Wert tatsächlich ein Wert ist (nicht null, nicht "", nicht 0 bei Nullable-Feldern)
      const isEmpty = newVal == null || newVal === "" || (typeof newVal === "number" && key !== "deep" && key !== "rem" && key !== "light" && key !== "wake" && key !== "totalSleep" && newVal === 0);
      // Schlafphasen können legitim 0 sein (z. B. kein REM gemessen), HRV/Ruhepuls dagegen sind bei 0/null definitiv "nicht gemessen"
      const shouldWrite = !isEmpty || existingWatch[key] == null || existingWatch[key] === "";

      if (shouldWrite && newVal !== existingWatch[key]) {
        mergedWatch[key] = newVal;
        hadChange = true;
      }
    }

    base.watch = mergedWatch;
    await saveDay(date, base);

    if (!existing) created++;
    else if (hadChange) merged++;
    else updated++;
  }
  return { created, merged, unchanged: updated, total: created + merged + updated };
}


// ——— CSV Parser für Health Auto Export ———
// Erwartet deutsches Format mit Spalten wie:
// Datum/Uhrzeit, Herzfrequenzvariabilität (ms), Ruhepuls (count/min),
// Schlafanalyse [Tief] (hr), Schlafanalyse [REM] (hr), Schlafanalyse [Kern] (hr),
// Schlafanalyse [Wach] (hr), Schlafanalyse [Total] (hr)
function parseHealthCSV(csvText) {
  const result = {};
  const lines = csvText.trim().split(/\r?\n/);
  if (lines.length < 2) return { days: result, unrecognized: ["CSV leer"] };

  // Header parsen
  const header = lines[0].split(",").map((h) => h.trim());

  // Spalten-Indizes finden (flexibel, funktioniert DE und EN)
  const findCol = (patterns) => {
    for (let i = 0; i < header.length; i++) {
      const h = header[i].toLowerCase();
      for (const p of patterns) {
        if (h.includes(p.toLowerCase())) return i;
      }
    }
    return -1;
  };

  const idx = {
    date: findCol(["datum", "date", "uhrzeit"]),
    hrv: findCol(["herzfrequenzvariabilität", "heart rate variability", "heart_rate_variability", "hrv"]),
    restingHR: findCol(["ruhepuls", "resting heart rate", "resting_heart_rate"]),
    deep: findCol(["[tief]", "[deep]"]),
    rem: findCol(["[rem]"]),
    core: findCol(["[kern]", "[core]", "[light]"]),
    wake: findCol(["[wach]", "[awake]"]),
    total: findCol(["[total]"]),
    inBed: findCol(["[im bett]", "[in bed]"]),
  };

  if (idx.date < 0) {
    return { days: result, unrecognized: ["Datumsspalte nicht gefunden"] };
  }

  // Einfacher CSV-Parser (keine Anführungszeichen nötig bei Health Auto Export)
  for (let i = 1; i < lines.length; i++) {
    const line = lines[i].trim();
    if (!line) continue;
    const cells = line.split(",");

    const rawDate = (cells[idx.date] || "").trim();
    if (!rawDate) continue;
    // Extrahiere YYYY-MM-DD aus "2026-04-17 00:00:00"
    const dateMatch = rawDate.match(/(\d{4}-\d{2}-\d{2})/);
    if (!dateMatch) continue;
    const date = dateMatch[1];

    const num = (i) => {
      if (i < 0) return null;
      const v = (cells[i] || "").trim();
      if (!v) return null;
      const n = Number(v);
      return isNaN(n) ? null : n;
    };

    const deep = num(idx.deep);
    const rem = num(idx.rem);
    const core = num(idx.core);
    const wake = num(idx.wake);
    const total = num(idx.total);
    const hrv = num(idx.hrv);
    const restingHR = num(idx.restingHR);

    // Mindestens ein Wert muss da sein, sonst Zeile überspringen
    if (deep == null && rem == null && core == null && wake == null && hrv == null && restingHR == null) continue;

    result[date] = {
      deep: deep != null ? Math.round(deep * 10) / 10 : 0,
      rem: rem != null ? Math.round(rem * 10) / 10 : 0,
      light: core != null ? Math.round(core * 10) / 10 : 0,
      wake: wake != null ? Math.round(wake * 10) / 10 : 0,
      totalSleep: total != null ? Math.round(total * 10) / 10 : 0,
      hrv: hrv != null ? Math.round(hrv * 10) / 10 : null,
      restingHR: restingHR != null ? Math.round(restingHR) : null,
    };
  }

  return { days: result, unrecognized: [] };
}


