// ——— Today ———
function TodayPage() {
  const [date, setDate] = useState(todayStr());
  const [day, setDay] = useState(emptyDay());
  const [configs, setConfigs] = useState({ supplements: [], medications: [], peptides: [] });
  const [loading, setLoading] = useState(true);
  const [savedFlash, setSavedFlash] = useState(false);
  const saveTimer = useRef(null);

  useEffect(() => {
    (async () => {
      setLoading(true);
      const [d, supps, meds, pepts] = await Promise.all([
        loadDay(date),
        getConfigCached("supplements"),
        getConfigCached("medications"),
        getConfigCached("peptides"),
      ]);
      setConfigs({ supplements: supps, medications: meds, peptides: pepts });
      setDay(d || emptyDay());
      setLoading(false);
    })();
  }, [date]);

  function persist(next) {
    setDay(next);
    if (saveTimer.current) clearTimeout(saveTimer.current);
    saveTimer.current = setTimeout(async () => {
      await saveDay(date, next);
      setSavedFlash(true);
      setTimeout(() => setSavedFlash(false), 1200);
    }, 300);
  }

  function toggleItem(type, id) {
    const current = day.active[type] || {};
    // Wenn noch nicht gesetzt, starte vom defaultActive-Wert
    const currentlyActive = id in current ? current[id] : TYPE_CONFIG[type].defaultActive;
    persist({
      ...day,
      active: {
        ...day.active,
        [type]: { ...current, [id]: !currentlyActive },
      },
    });
  }

  function isActive(type, id) {
    const current = day.active[type] || {};
    return id in current ? current[id] : TYPE_CONFIG[type].defaultActive;
  }

  async function addCustomItem(type, name, dose) {
    const id = `custom-${Date.now()}-${Math.random().toString(36).slice(2, 6)}`;
    const newItem = { id, name: name.trim(), dose: dose.trim(), isCustom: true };
    const newList = [...configs[type], newItem];
    setConfigs({ ...configs, [type]: newList });
    await saveConfig(type, newList);
  }

  async function deleteCustomItem(type, id) {
    const newList = configs[type].filter((it) => it.id !== id);
    setConfigs({ ...configs, [type]: newList });
    await saveConfig(type, newList);
    // aus aktiv-Status des Tages entfernen
    const currentActive = { ...(day.active[type] || {}) };
    delete currentActive[id];
    persist({
      ...day,
      active: { ...day.active, [type]: currentActive },
    });
  }

  if (loading) return <div style={{ color: "var(--text-soft)" }}>Lädt…</div>;

  const s = day.sleep;
  const m = day.meal;

  const countActive = (type) =>
    configs[type].filter((it) => isActive(type, it.id)).length;

  return (
    <div>
      <div className="flex items-center justify-between mb-8 date-row">
        <div>
          <div className="eyebrow mb-1">Letzte Nacht</div>
          <h1 className="font-display" style={{ fontSize: 36, lineHeight: 1.05 }}>
            {formatDate(date)}
          </h1>
        </div>
        <div className="flex items-center gap-3">
          {savedFlash && (
            <span className="save-pill">
              <Check size={12} /> Gespeichert
            </span>
          )}
          <input
            type="date"
            className="input"
            style={{ width: "auto" }}
            value={date}
            onChange={(e) => setDate(e.target.value)}
          />
        </div>
      </div>

      <Section title="Schlaf" eyebrow="01 · Nacht">
        <div className="card">
          <div className="mb-6">
            <div className="eyebrow mb-3">Subjektiv wahrgenommene Qualität</div>
            <div className="flex items-center gap-6">
              <input
                type="range"
                min={1}
                max={10}
                value={s.quality}
                onChange={(e) => persist({ ...day, sleep: { ...s, quality: Number(e.target.value) } })}
                className="slider"
              />
              <div className="font-display" style={{ fontSize: 40, minWidth: 72, textAlign: "right" }}>
                {s.quality}
                <span style={{ color: "var(--text-soft)", fontSize: 20 }}>/10</span>
              </div>
            </div>
            <div className="flex justify-between mt-2" style={{ color: "var(--text-soft)", fontSize: 13 }}>
              <span>zerschlagen</span>
              <span>ausgeruht</span>
            </div>
            <div style={{ fontSize: 12, color: "var(--text-soft)", marginTop: 8, fontStyle: "italic" }}>
              Dein Gefühl — kann sich von den objektiven Apple-Watch-Daten unterscheiden.
            </div>
          </div>

          <div className="mb-6">
            <div className="eyebrow mb-3">Schlafplatz</div>
            <div className="flex gap-2 flex-wrap">
              {[
                ["hard", "Zuhause · hart"],
                ["soft", "Zuhause · weich"],
                ["away", "Auswärts"],
              ].map(([k, label]) => (
                <button
                  key={k}
                  className={`chip ${s.bed === k ? "chip-active" : ""}`}
                  onClick={() => persist({ ...day, sleep: { ...s, bed: k } })}
                >
                  {label}
                </button>
              ))}
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4 items-start">
            <div>
              <div className="eyebrow mb-3">Stress gestern</div>
              <div className="flex items-center gap-4">
                <input
                  type="range"
                  min={1}
                  max={10}
                  value={s.stress}
                  onChange={(e) => persist({ ...day, sleep: { ...s, stress: Number(e.target.value) } })}
                  className="slider"
                />
                <div className="font-mono text-xl" style={{ minWidth: 32 }}>{s.stress}</div>
              </div>
            </div>
            <div>
              <div className="eyebrow mb-3">Koffein nach 12:30</div>
              <div className="flex gap-2">
                <button
                  className={`chip ${!s.caffeineAfter1230 ? "chip-active" : ""}`}
                  onClick={() => persist({ ...day, sleep: { ...s, caffeineAfter1230: false } })}
                >
                  Nein
                </button>
                <button
                  className={`chip ${s.caffeineAfter1230 ? "chip-active chip-accent" : ""}`}
                  onClick={() => persist({ ...day, sleep: { ...s, caffeineAfter1230: true } })}
                >
                  Ja
                </button>
              </div>
            </div>
          </div>
        </div>
      </Section>

      <Section title="Abendmahlzeit" eyebrow="02 · Essen">
        <div className="card">
          <div className="grid grid-cols-2 gap-4 mb-6">
            <div>
              <div className="eyebrow mb-2">
                <Clock size={10} style={{ display: "inline", marginRight: 4 }} /> Zeit
              </div>
              <input
                type="time"
                className="input"
                value={m.time}
                onChange={(e) => persist({ ...day, meal: { ...m, time: e.target.value } })}
              />
            </div>
            <div>
              <div className="eyebrow mb-2">Histamin-Score</div>
              <div className="flex items-center gap-3">
                <input
                  type="range"
                  min={0}
                  max={5}
                  value={m.histamine}
                  onChange={(e) => persist({ ...day, meal: { ...m, histamine: Number(e.target.value) } })}
                  className="slider slider-accent"
                />
                <div className="font-mono text-xl" style={{ minWidth: 28 }}>{m.histamine}</div>
              </div>
            </div>
          </div>
          <div
            className="card-tight"
            style={{ background: "var(--accent-soft)", borderColor: "var(--accent)" }}
          >
            <div className="eyebrow mb-1" style={{ color: "var(--accent-dark)" }}>
              Score {m.histamine}/5
            </div>
            <div style={{ fontSize: 17, fontWeight: 500, color: "var(--accent-dark)" }}>
              {HISTAMIN_HINT[m.histamine]}
            </div>
          </div>
        </div>
      </Section>

      <ItemSection
        title="Supplements"
        eyebrow="03 · Einnahme"
        type="supplements"
        items={configs.supplements}
        isActive={isActive}
        toggleItem={toggleItem}
        addCustomItem={addCustomItem}
        deleteCustomItem={deleteCustomItem}
        countActive={countActive("supplements")}
        total={configs.supplements.length}
      />

      <ItemSection
        title="Medikamente"
        eyebrow="04 · Einnahme"
        type="medications"
        items={configs.medications}
        isActive={isActive}
        toggleItem={toggleItem}
        addCustomItem={addCustomItem}
        deleteCustomItem={deleteCustomItem}
        countActive={countActive("medications")}
      />

      <ItemSection
        title="Peptide am Abend"
        eyebrow="05 · Einnahme"
        type="peptides"
        items={configs.peptides}
        isActive={isActive}
        toggleItem={toggleItem}
        addCustomItem={addCustomItem}
        deleteCustomItem={deleteCustomItem}
        countActive={countActive("peptides")}
      />

      <WatchDataSection day={day} />

      <Section title="Notizen" eyebrow="07 · Frei">
        <textarea
          className="input"
          rows={4}
          placeholder="Was ist dir aufgefallen? Träume, Gedanken, Besonderheiten…"
          value={day.notes}
          onChange={(e) => persist({ ...day, notes: e.target.value })}
          style={{ resize: "vertical" }}
        />
      </Section>
    </div>
  );
}

function Section({ title, eyebrow, hint, children }) {
  return (
    <section className="mb-10">
      <div className="section-head">
        <div>
          <div className="eyebrow mb-1">{eyebrow}</div>
          <div className="section-title">{title}</div>
        </div>
        {hint && <div className="eyebrow">{hint}</div>}
      </div>
      {children}
    </section>
  );
}

function ItemSection({ title, eyebrow, type, items, isActive, toggleItem, addCustomItem, deleteCustomItem, countActive, total }) {
  const [adding, setAdding] = useState(false);
  const [name, setName] = useState("");
  const [dose, setDose] = useState("");
  const [confirmDelete, setConfirmDelete] = useState(null);

  const hint = total != null
    ? `${countActive}/${total} aktiv`
    : `${countActive} genommen`;

  function handleAdd() {
    if (!name.trim()) return;
    addCustomItem(type, name, dose);
    setName("");
    setDose("");
    setAdding(false);
  }

  return (
    <Section title={title} eyebrow={eyebrow} hint={hint}>
      <div className="grid grid-cols-2 gap-3">
        {items.map((it) => (
          <div
            key={it.id}
            className={`row-toggle ${isActive(type, it.id) ? "row-toggle-active" : ""}`}
            onClick={() => toggleItem(type, it.id)}
          >
            <div style={{ minWidth: 0, flex: 1 }}>
              <div style={{ fontWeight: 500, fontSize: 15, lineHeight: 1.2 }}>{it.name}</div>
              {it.dose && (
                <div className="font-mono" style={{ fontSize: 12, color: "var(--text-soft)", marginTop: 3 }}>
                  {it.dose}
                </div>
              )}
            </div>
            <div className={`checkbox-visual ${isActive(type, it.id) ? "checkbox-visual-active" : ""}`}>
              {isActive(type, it.id) && <Check size={14} strokeWidth={3} />}
            </div>
            {it.isCustom && (
              <button
                className="del-btn"
                onClick={(e) => {
                  e.stopPropagation();
                  if (confirmDelete === it.id) {
                    deleteCustomItem(type, it.id);
                    setConfirmDelete(null);
                  } else {
                    setConfirmDelete(it.id);
                    setTimeout(() => setConfirmDelete(null), 3000);
                  }
                }}
                title={confirmDelete === it.id ? "Nochmal klicken zum Löschen" : "Löschen"}
                style={{
                  opacity: confirmDelete === it.id ? 1 : undefined,
                  background: confirmDelete === it.id ? "var(--warn)" : undefined,
                }}
              >
                <X size={11} strokeWidth={3} />
              </button>
            )}
          </div>
        ))}
      </div>

      {adding ? (
        <div className="card-tight mt-3" style={{ padding: 16 }}>
          <div className="eyebrow mb-3">Eigenen Eintrag hinzufügen</div>
          <div className="grid grid-cols-2 gap-3 mb-3">
            <input
              className="input"
              placeholder="Name (z. B. Zink Bisglycinat)"
              value={name}
              onChange={(e) => setName(e.target.value)}
              autoFocus
            />
            <input
              className="input"
              placeholder="Dosis (z. B. 15mg)"
              value={dose}
              onChange={(e) => setDose(e.target.value)}
              onKeyDown={(e) => e.key === "Enter" && handleAdd()}
            />
          </div>
          <div className="flex gap-2">
            <button className="btn btn-accent" onClick={handleAdd} disabled={!name.trim()}>
              <Plus size={14} /> Hinzufügen
            </button>
            <button className="btn" onClick={() => { setAdding(false); setName(""); setDose(""); }}>
              Abbrechen
            </button>
          </div>
        </div>
      ) : (
        <button className="add-btn mt-3" onClick={() => setAdding(true)}>
          <Plus size={16} /> Neuen Eintrag hinzufügen
        </button>
      )}
    </Section>
  );
}



