// ═══════════════════════════════════════════════════════════════
// ——— Chart Komponenten (SVG, ohne externe Library) ———
// ═══════════════════════════════════════════════════════════════

function TimelineChart({ history, field, label, maxValue, color = "var(--accent)" }) {
  // Letzte 30 Tage als Linie
  const recent = history.slice(-30);
  const data = recent
    .map((h) => ({ date: h.date, value: field(h) }))
    .filter((d) => d.value != null);

  if (data.length < 2) {
    return (
      <div className="card-tight" style={{ textAlign: "center", color: "var(--text-soft)", fontSize: 13 }}>
        Zu wenig Daten für Zeitverlauf ({data.length})
      </div>
    );
  }

  const W = 600, H = 160, PAD_L = 30, PAD_R = 12, PAD_T = 12, PAD_B = 24;
  const innerW = W - PAD_L - PAD_R;
  const innerH = H - PAD_T - PAD_B;
  const max = maxValue || Math.max(...data.map(d => d.value)) * 1.1;
  const min = 0;

  const points = data.map((d, i) => {
    const x = PAD_L + (i / (data.length - 1)) * innerW;
    const y = PAD_T + (1 - (d.value - min) / (max - min)) * innerH;
    return { x, y, ...d };
  });

  const path = points.map((p, i) => (i === 0 ? "M" : "L") + p.x + "," + p.y).join(" ");
  const avgValue = data.reduce((s, d) => s + d.value, 0) / data.length;
  const avgY = PAD_T + (1 - (avgValue - min) / (max - min)) * innerH;

  return (
    <div className="card-tight" style={{ padding: 16 }}>
      <div className="flex items-center justify-between mb-2">
        <div style={{ fontWeight: 500, fontSize: 14 }}>{label}</div>
        <div className="font-mono" style={{ fontSize: 12, color: "var(--text-soft)" }}>
          Ø {avgValue.toFixed(1)} · n={data.length}
        </div>
      </div>
      <svg viewBox={`0 0 ${W} ${H}`} style={{ width: "100%", height: "auto", display: "block" }}>
        {/* Grid */}
        {[0, 0.25, 0.5, 0.75, 1].map((t) => {
          const y = PAD_T + t * innerH;
          return (
            <line key={t} x1={PAD_L} y1={y} x2={W - PAD_R} y2={y}
              stroke="var(--line)" strokeWidth="1" strokeDasharray={t === 0 || t === 1 ? "" : "2,3"} />
          );
        })}
        {/* Y-Achse Labels */}
        <text x={PAD_L - 6} y={PAD_T + 4} fill="var(--text-soft)" fontSize="10" textAnchor="end">{max.toFixed(0)}</text>
        <text x={PAD_L - 6} y={PAD_T + innerH + 4} fill="var(--text-soft)" fontSize="10" textAnchor="end">{min}</text>
        {/* Durchschnitt-Linie */}
        <line x1={PAD_L} y1={avgY} x2={W - PAD_R} y2={avgY}
          stroke="var(--text-soft)" strokeWidth="1" strokeDasharray="4,3" opacity="0.5" />
        <text x={W - PAD_R - 2} y={avgY - 4} fill="var(--text-soft)" fontSize="9" textAnchor="end">Ø</text>
        {/* Datenlinie */}
        <path d={path} fill="none" stroke={color} strokeWidth="2" strokeLinejoin="round" strokeLinecap="round" />
        {/* Punkte */}
        {points.map((p, i) => (
          <circle key={i} cx={p.x} cy={p.y} r="3" fill={color} stroke="white" strokeWidth="1.5">
            <title>{formatShortDate(p.date)}: {p.value}</title>
          </circle>
        ))}
        {/* X-Achse: erster und letzter Tag */}
        <text x={PAD_L} y={H - 6} fill="var(--text-soft)" fontSize="10" textAnchor="start">
          {formatShortDate(points[0].date)}
        </text>
        <text x={W - PAD_R} y={H - 6} fill="var(--text-soft)" fontSize="10" textAnchor="end">
          {formatShortDate(points[points.length - 1].date)}
        </text>
      </svg>
    </div>
  );
}

function ScatterChart({ pairs, xLabel, yLabel, xMax, yMax }) {
  if (pairs.length < 3) {
    return (
      <div className="card-tight" style={{ textAlign: "center", color: "var(--text-soft)", fontSize: 13 }}>
        Zu wenig Daten für Scatter-Plot ({pairs.length})
      </div>
    );
  }

  const W = 360, H = 280, PAD_L = 40, PAD_R = 16, PAD_T = 16, PAD_B = 36;
  const innerW = W - PAD_L - PAD_R;
  const innerH = H - PAD_T - PAD_B;

  const xs = pairs.map((p) => p[0]);
  const ys = pairs.map((p) => p[1]);
  const xMn = 0;
  const xMx = xMax || Math.max(...xs) * 1.1;
  const yMn = 0;
  const yMx = yMax || Math.max(...ys) * 1.1;

  const points = pairs.map((p) => ({
    x: PAD_L + ((p[0] - xMn) / (xMx - xMn)) * innerW,
    y: PAD_T + (1 - (p[1] - yMn) / (yMx - yMn)) * innerH,
    raw: p,
  }));

  // Regressionslinie (Least Squares)
  const n = pairs.length;
  const meanX = xs.reduce((s, v) => s + v, 0) / n;
  const meanY = ys.reduce((s, v) => s + v, 0) / n;
  let num = 0, den = 0;
  for (let i = 0; i < n; i++) {
    num += (xs[i] - meanX) * (ys[i] - meanY);
    den += (xs[i] - meanX) * (xs[i] - meanX);
  }
  const slope = den !== 0 ? num / den : 0;
  const intercept = meanY - slope * meanX;
  const lineY1 = slope * xMn + intercept;
  const lineY2 = slope * xMx + intercept;
  const lineX1px = PAD_L;
  const lineY1px = PAD_T + (1 - (lineY1 - yMn) / (yMx - yMn)) * innerH;
  const lineX2px = PAD_L + innerW;
  const lineY2px = PAD_T + (1 - (lineY2 - yMn) / (yMx - yMn)) * innerH;

  return (
    <div className="card-tight" style={{ padding: 16 }}>
      <svg viewBox={`0 0 ${W} ${H}`} style={{ width: "100%", height: "auto", display: "block" }}>
        {/* Grid */}
        {[0, 0.25, 0.5, 0.75, 1].map((t) => {
          const y = PAD_T + t * innerH;
          return (
            <line key={"h" + t} x1={PAD_L} y1={y} x2={W - PAD_R} y2={y}
              stroke="var(--line)" strokeWidth="1" strokeDasharray={t === 0 || t === 1 ? "" : "2,3"} />
          );
        })}
        {/* Y-Ticks */}
        <text x={PAD_L - 6} y={PAD_T + 4} fill="var(--text-soft)" fontSize="10" textAnchor="end">{yMx.toFixed(0)}</text>
        <text x={PAD_L - 6} y={PAD_T + innerH + 4} fill="var(--text-soft)" fontSize="10" textAnchor="end">{yMn}</text>
        {/* X-Ticks */}
        <text x={PAD_L} y={H - 18} fill="var(--text-soft)" fontSize="10" textAnchor="start">{xMn}</text>
        <text x={W - PAD_R} y={H - 18} fill="var(--text-soft)" fontSize="10" textAnchor="end">{xMx.toFixed(0)}</text>
        {/* Regressionslinie */}
        <line x1={lineX1px} y1={lineY1px} x2={lineX2px} y2={lineY2px}
          stroke="var(--accent)" strokeWidth="2" strokeDasharray="4,3" opacity="0.6" />
        {/* Punkte */}
        {points.map((p, i) => (
          <circle key={i} cx={p.x} cy={p.y} r="4" fill="var(--text)" fillOpacity="0.6" stroke="white" strokeWidth="1">
            <title>{xLabel}: {p.raw[0]} / {yLabel}: {p.raw[1]}</title>
          </circle>
        ))}
        {/* Achsenbeschriftungen */}
        <text x={W / 2} y={H - 4} fill="var(--text-dim)" fontSize="11" textAnchor="middle">{xLabel}</text>
        <text x={10} y={H / 2} fill="var(--text-dim)" fontSize="11" textAnchor="middle"
          transform={`rotate(-90, 10, ${H / 2})`}>{yLabel}</text>
      </svg>
    </div>
  );
}

function BarCompareChart({ items, valueLabel = "Ø Schlafqualität" }) {
  // items: [{ name, avgA, avgB, nA, nB, labelA, labelB }]
  if (items.length === 0) return null;

  const W = 600, rowH = 56, PAD_L = 160, PAD_R = 60, PAD_T = 20, PAD_B = 20;
  const H = PAD_T + PAD_B + items.length * rowH;
  const innerW = W - PAD_L - PAD_R;
  const maxVal = 10; // Schlafqualität max

  return (
    <div className="card-tight" style={{ padding: 16 }}>
      <div className="eyebrow mb-3">{valueLabel} · Mit vs. Ohne</div>
      <svg viewBox={`0 0 ${W} ${H}`} style={{ width: "100%", height: "auto", display: "block" }}>
        {items.map((it, i) => {
          const yBase = PAD_T + i * rowH;
          const widthA = (it.avgA / maxVal) * innerW;
          const widthB = (it.avgB / maxVal) * innerW;
          const better = it.avgA > it.avgB;
          return (
            <g key={i}>
              {/* Label */}
              <text x={PAD_L - 10} y={yBase + 20} fill="var(--text)" fontSize="13" fontWeight="500" textAnchor="end">
                {it.name.length > 20 ? it.name.slice(0, 18) + "…" : it.name}
              </text>
              {/* Mit-Balken */}
              <rect x={PAD_L} y={yBase + 8} width={widthA} height="14"
                fill={better ? "var(--positive)" : "var(--warn)"} rx="2" />
              <text x={PAD_L + widthA + 4} y={yBase + 19} fill="var(--text)" fontSize="11" fontWeight="500">
                {it.avgA.toFixed(1)}
              </text>
              <text x={PAD_L - 4} y={yBase + 19} fill="var(--text-soft)" fontSize="9" textAnchor="end"
                style={{ display: "none" }}>mit</text>
              {/* Ohne-Balken */}
              <rect x={PAD_L} y={yBase + 26} width={widthB} height="14"
                fill="var(--muted)" rx="2" />
              <text x={PAD_L + widthB + 4} y={yBase + 37} fill="var(--text-dim)" fontSize="11">
                {it.avgB.toFixed(1)}
              </text>
              {/* Legende pro Zeile */}
              <text x={PAD_L - 4} y={yBase + 37} fill="var(--text-soft)" fontSize="9" textAnchor="end">n={it.nA}/{it.nB}</text>
            </g>
          );
        })}
        {/* Axis grid */}
        {[0, 0.5, 1].map((t) => {
          const x = PAD_L + t * innerW;
          return (
            <line key={t} x1={x} y1={PAD_T} x2={x} y2={H - PAD_B}
              stroke="var(--line)" strokeWidth="1" strokeDasharray={t === 0 || t === 1 ? "" : "2,3"} />
          );
        })}
      </svg>
      <div className="flex gap-4 mt-2" style={{ fontSize: 11, color: "var(--text-soft)" }}>
        <span><span style={{ display: "inline-block", width: 10, height: 10, background: "var(--positive)", borderRadius: 2, marginRight: 4, verticalAlign: "middle" }}></span>mit (besser)</span>
        <span><span style={{ display: "inline-block", width: 10, height: 10, background: "var(--warn)", borderRadius: 2, marginRight: 4, verticalAlign: "middle" }}></span>mit (schlechter)</span>
        <span><span style={{ display: "inline-block", width: 10, height: 10, background: "var(--muted)", borderRadius: 2, marginRight: 4, verticalAlign: "middle" }}></span>ohne</span>
      </div>
    </div>
  );
}

function SleepPhasesDonut({ deep, rem, light, wake }) {
  const total = (deep || 0) + (rem || 0) + (light || 0) + (wake || 0);
  if (total === 0) return null;

  const size = 160, stroke = 18, radius = (size - stroke) / 2;
  const circumference = 2 * Math.PI * radius;

  const segments = [
    { value: deep || 0, color: "#6d28d9", label: "Deep" },
    { value: rem || 0, color: "#ea580c", label: "REM" },
    { value: light || 0, color: "#8fb896", label: "Light" },
    { value: wake || 0, color: "#d97a7a", label: "Wach" },
  ];

  let offset = 0;
  return (
    <div className="card-tight" style={{ padding: 16 }}>
      <div className="eyebrow mb-3">Schlafphasen-Verteilung</div>
      <div className="flex items-center gap-6">
        <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
          <circle cx={size/2} cy={size/2} r={radius} fill="none" stroke="var(--line)" strokeWidth={stroke} />
          {segments.map((s, i) => {
            const frac = s.value / total;
            const length = frac * circumference;
            const circ = (
              <circle key={i} cx={size/2} cy={size/2} r={radius} fill="none"
                stroke={s.color} strokeWidth={stroke}
                strokeDasharray={`${length} ${circumference - length}`}
                strokeDashoffset={-offset}
                transform={`rotate(-90 ${size/2} ${size/2})`}
              />
            );
            offset += length;
            return circ;
          })}
          <text x={size/2} y={size/2 - 4} textAnchor="middle" fill="var(--text)" fontSize="20" fontWeight="600">
            {total.toFixed(1)}h
          </text>
          <text x={size/2} y={size/2 + 14} textAnchor="middle" fill="var(--text-soft)" fontSize="10">
            Gesamt
          </text>
        </svg>
        <div style={{ flex: 1 }}>
          {segments.filter(s => s.value > 0).map((s, i) => (
            <div key={i} style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: "4px 0", fontSize: 13 }}>
              <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                <div style={{ width: 10, height: 10, borderRadius: 2, background: s.color }}></div>
                <span>{s.label}</span>
              </div>
              <div className="font-mono" style={{ color: "var(--text-dim)" }}>
                {s.value.toFixed(1)}h <span style={{ color: "var(--text-soft)", fontSize: 11 }}>({((s.value/total)*100).toFixed(0)}%)</span>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

